    logic [95:0] in_;
    logic [95:0] out_;
    assign in_[31:0] = in_0;
    assign in_[63:32] = in_1;
    assign in_[95:64] = in_2;
    assign out_0 = out_[31:0];
    assign out_1 = out_[63:32];
    assign out_2 = out_[95:64];
    top top_i(in_, out_);
endmodule
```

